export type PracticeItem = {
  id: number
  category: string
  title: string
  latex: string
  note: string
  meaning?: string
}

function makeCategory(category: string, items: Omit<PracticeItem, 'category'>[]) {
  return items.map((item) => ({ ...item, category }))
}

